/**
 * Internal types not exported from the package and are used internally.
 */
/**
 * Merchant information for express checkout methods (Apple Pay, Google Pay)
 * This information is typically provided by the parent component and not
 * configured directly by the end user.
 */
export interface ExpressMerchantInfo {
    /** The merchant identifier for payment processing */
    merchantId?: string;
    /** The display name of the merchant */
    merchantName?: string;
    /** Allowed card brands for payment (e.g., ['VISA', 'MASTERCARD']) */
    cardBrands?: string[];
    /** Whether to use test/sandbox mode */
    testMode?: boolean;
}
